noncompliant:
// Redundant inline with constexpr
inline constexpr int addOne(int n) { // Noncompliant - inline is redundant
    return n + 1;
}

inline constexpr double square(double x) { // Noncompliant
    return x * x;
}

class Calculator {
public:
    inline constexpr static int multiply(int a, int b) { // Noncompliant
        return a * b;
    }
};

compliant:
// Proper constexpr usage
constexpr int addOne(int n) { // Compliant - constexpr implies inline
    return n + 1;
}

constexpr double square(double x) { // Compliant
    return x * x;
}

class Calculator {
public:
    constexpr static int multiply(int a, int b) { // Compliant
        return a * b;
    }
};
